  return 2024 - birthYear;
};

const isRetired = function(age) {
  return age >= 65;
};

// 
const myAge = calcAge(1955);
console.log(myAge);            // 69
console.log(isRetired(myAge)); // true

const age2 = calcAge(1990);
console.log(age2);             // 34
